    public partial class EarningComponentService : BaseService<EarningComponent>, IEarningComponentService
    {
        public EarningComponentService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task Validation(EarningComponent item, Result<EarningComponent> executionResult)
        {
            if (await UOW.GetRepositoryAsync<EarningComponent>().HasRecordsAsync(x => x.Name == item.Name && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(EarningComponent.Name), "Name already exists"));
            }
        }
        public override async Task<EarningComponent> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<EarningComponent>().SingleAsync(
                predicate: x => x.ID == id,
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<EarningComponent>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<EarningComponent>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<EarningComponent>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<EarningComponent>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Name.Contains(search.Name)),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "EarningType", ascending: !search.IsDescend);
        }
    }
